from collections import Counter

class Solution(object):
    def findCommonResponse(self, responses):
        freq = Counter()
        for day in responses:
            for r in set(day):  # deduplicate within day
                freq[r] += 1
        best_count = max(freq.values())
        return min(r for r, c in freq.items() if c == best_count)
